const scrollMarginImageDivClassName="kakaopage_viewer_next_chapter";const scrollMarginContainerDivClassName=`${scrollMarginImageDivClassName}_container`;function addScrollMarginWithImage(scrollMargin,imageBase64,imageSize,imagePlacement){const containerDivElement=document.createElement("div");containerDivElement.className=scrollMarginContainerDivClassName;Object.assign(containerDivElement.style,{position:"relative",pointerEvents:"none",WebkitUserSelect:"none",userSelect:"none"});const imageDivElement=document.createElement("div");imageDivElement.className=scrollMarginImageDivClassName;Object.assign(imageDivElement.style,{position:"absolute",left:"0",right:"0",bottom:`${imagePlacement}px`,marginLeft:"auto",marginRight:"auto",width:`${imageSize.width}px`,height:`${imageSize.height}px`,backgroundImage:`url('data:image/png;base64, ${imageBase64}')`,pointerEvents:"none",WebkitUserSelect:"none",userSelect:"none"});containerDivElement.appendChild(imageDivElement);function updateScrollMarginHeight(){const clientHeight=getClientHeight();const bodyContentHeight=document.body.offsetHeight-containerDivElement.offsetHeight;const emptySpace=Math.max(0,clientHeight-bodyContentHeight);const newHeight=clientHeight*scrollMargin+emptySpace;const newHeightPx=`${newHeight.toFixed(0)}px`;if(newHeightPx!==containerDivElement.style.height){containerDivElement.style.height=newHeightPx}}const observer=new ResizeObserver(()=>{updateScrollMarginHeight()});observer.observe(document.body);function initialize(){document.body.appendChild(containerDivElement);updateScrollMarginHeight()}if(document.readyState==="loading"){window.addEventListener("DOMContentLoaded",initialize)}else{initialize()}}function refreshScrollMarginImage(){const elements=document.querySelectorAll(`.${scrollMarginImageDivClassName}`);if(elements.length===0){return}elements.forEach(element=>{element.classList.remove(scrollMarginImageDivClassName)});setTimeout(()=>{elements.forEach(element=>{element.classList.add(scrollMarginImageDivClassName)})},10)}function getScrollMarginHeight(){const element=document.querySelector(`.${scrollMarginContainerDivClassName}`);if(element&&typeof element.offsetHeight!=="undefined"){return element.offsetHeight}return 0}function getContentScrollHeight(){const scrollHeight=document.scrollingElement.scrollHeight;return Math.max(0,scrollHeight-getScrollMarginHeight())}